<?xml version="1.0" encoding="UTF-8"?>
<changes>
  <change>
    <file>components/uiComponents.tsx</file>
    <description>Update the ResetKeyModal to reflect the new workflow with openSelectKey</description>
    <content><![CDATA[import React from 'react';
import { Modal, Button } from '@blueprintjs/core';

interface ResetKeyModalProps {
  isOpen: boolean;
  onClose: () => void;
  onConfirm: () => void;
}

export const ResetKeyModal: React.FC<ResetKeyModalProps> = ({ isOpen, onClose, onConfirm }) => {
  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Cảnh báo API Key">
      <div className="bp4-dialog-body">
        Bạn sẽ ngắt kết nối API Key để tránh phát sinh chi phí không mong muốn. Để quản lý API Key, nhấn vào nút bên dưới.
      </div>
      <div className="bp4-dialog-footer">
        <div className="bp4-dialog-footer-actions">
          <Button onClick={onClose}>Hủy bỏ</Button>
          <Button intent="primary" onClick={onConfirm}>Mở cài đặt Key</Button>
        </div>
      </div>
    </Modal>
  );
};
]]></content>
  </change>
  <change>
    <file>App.tsx</file>
    <description>Integrate openSelectKey and update confirmSwitchToV2</description>
    <content><![CDATA[import React, { useState, useEffect } from 'react';
import { Button, Intent } from '@blueprintjs/core';
import { ResetKeyModal } from './components/uiComponents';
import { openSelectKey } from './keyManager';
import { useGoogleGenAI } from './GoogleGenAIContext';

function App() {
  const [currentVersion, setCurrentVersion] = useState<'v2' | 'v3'>('v3');
  const [isResetKeyModalOpen, setIsResetKeyModalOpen] = useState(false);
  const { resetApiKey } = useGoogleGenAI();

  useEffect(() => {
    // Check if the API key is not present when switching to v2, open the modal
    if (currentVersion === 'v2' && !localStorage.getItem('API_KEY')) {
      setIsResetKeyModalOpen(true);
    }
  }, [currentVersion]);

  const confirmSwitchToV2 = async () => {
    setIsResetKeyModalOpen(false); // Close the modal first
    await openSelectKey(); // Open key selection process
    setCurrentVersion('v2'); // Switch version
  };

  return (
    <div className="App">
      <h1>API Key Management</h1>
      <Button
        intent={currentVersion === 'v2' ? Intent.PRIMARY : Intent.SECONDARY}
        onClick={() => {
          if (currentVersion === 'v3') {
            setIsResetKeyModalOpen(true);
          } else {
            setCurrentVersion('v3');
          }
        }}
      >
        {currentVersion === 'v3' ? 'Switch to v2' : 'Switch to v3'}
      </Button>

      <ResetKeyModal
        isOpen={isResetKeyModalOpen}
        onClose={() => setIsResetKeyModalOpen(false)}
        onConfirm={confirmSwitchToV2}
      />
    </div>
  );
}

export default App;
]]></content>
  </change>
</changes>
```

